form:Form.form:Scripts:
		function Preview()
{               
 	if (Ctrl("list2").TotalRowsCount()==0)
 	{             
 		alert("No hay legajos filtrados.");
 		return false;
 	} 	
 	Ctrl('legajos').DelAllRow();
 	for (key in arrB) Ctrl('legajos').AddRow().SetAttr('id', key.substr(1));	

	var param = "<FILTRO oi_empresa=\""+Ctrl("empresa").GetXValue() +"\"  f_ini=\""+Ctrl("f_ini").GetXValue() +"\" f_fin=\""+Ctrl("f_fin").GetXValue()+"\"><ROWS>";
	for (key in arrB) param = param + "<ROW id=\""+key.substr(1) +"\"/>";
	param = param + "</ROWS></FILTRO>"

	openNewFlowWait('NucleusRH.Base.Sanciones.Interface.INTERFACE.guia.flow',"HELP",param,new ObjtectResult(),"S");
}

function Ejecutar()
{               
 	if (Ctrl("list2").TotalRowsCount()==0)
 	{             
 		alert("No hay legajos filtrados.");
 		return false;
 	}

 	Ctrl('legajos').DelAllRow();
 	for (key in arrB) Ctrl('legajos').AddRow().SetAttr('id', key.substr(1));

	Ctrl("main").DoEvent("ok");
}

function ObjtectResult()
{        
	this.processResult= function(xmlin)
		{    
		}
}
